 60	void decode_procstat(char *record, int debug, telnet_printfunc_t prnt, webdatadef_t *tdata)
 61	{
 62	char prntline[160];
 63	char *procfile_fields;
 64	char *strtokptr;
 65	char *lptr;
 66	int fieldcnt;
 67	char toksep[2];
 68	
 69	fieldcnt = 0;
 70	procfile_fields = strtok_r(record, " ", &strtokptr);
 71	lptr = prntline;
 72	/*http://man7.org/linux/man-pages/man5/proc.5.html gives the structure of the stat file */
 73	int priority = 0;
 74	int nice = 0;
 75	while (procfile_fields != NULL && fieldcnt < 42) {
 76	  long int policy;
 77	  if (strlen(procfile_fields) == 0)
 78	    continue;
 79	  fieldcnt++;
 80	  sprintf(toksep, " ");
 81	  switch (fieldcnt) {
 82	    case 1: /* id */
 83	      if (tdata != NULL) {
 84	        tdata->lines[tdata->numlines].val[0] = strdup(procfile_fields);
 85	      }
 86	      lptr += sprintf(lptr, "%9.9s ", procfile_fields);
 87	      sprintf(toksep, ")");
 88	      break;
 89	    case 2: /* name */
 90	      if (tdata != NULL) {
 91	        tdata->lines[tdata->numlines].val[1] = strdup(procfile_fields);
 92	      }
 93	      lptr += sprintf(lptr, "%20.20s ", procfile_fields + 1);
 94	      break;
 95	    case 3: // thread state
 96	      lptr += sprintf(lptr, "  %c   ", procfile_fields[0]);
 97	      break;
 98	    case 14: // time in user mode
 99	    case 15: // time in kernel mode
100	      lptr += sprintf(lptr, "%9.9s ", procfile_fields);
101	      break;
102	    case 18: // priority column index 2 in tdata, -2 to -100 (1, min to 99, highest prio)
103	      priority = strtol(procfile_fields, NULL, 0);
104	    case 19: // nice	  column index 3 in tdata  0 to 39 (-20, highest prio, to 19)
105	      if (tdata != NULL) {
106	        tdata->lines[tdata->numlines].val[fieldcnt - 16] = strdup(procfile_fields);
107	      }
108	      lptr += sprintf(lptr, "%3.3s ", procfile_fields);
109	      nice = strtol(procfile_fields, NULL, 0);
110	      break;
111	    case 23: // vsize
112	      lptr += sprintf(lptr, "%9.9s ", procfile_fields);
113	      break;
114	    case 39: // processor
115	      if (tdata != NULL) {
116	        tdata->lines[tdata->numlines].val[4] = strdup(procfile_fields);
117	      }
118	      lptr += sprintf(lptr, " %2.2s  ", procfile_fields);
119	      break;
120	    case 41: // policy
121	      lptr += sprintf(lptr, "%3.3s ", procfile_fields);
122	      policy = strtol(procfile_fields, NULL, 0);
123	      char strschedp[64];
124	      switch (policy) {
125	        case SCHED_FIFO:
126	          snprintf(strschedp, sizeof(strschedp), "%s ", "rt:fifo");
127	          priority = priority + 1; // in /proc file system priority 1 to 99 mapped to -2 to -100
128	          break;
129	        case SCHED_OTHER:
130	          snprintf(strschedp, sizeof(strschedp), "%s ", "other");
131	          priority = nice - NICE_MIN; // linux nice is -20 to 19
132	          break;
133	        case SCHED_IDLE:
134	          snprintf(strschedp, sizeof(strschedp), "%s ", "idle");
135	          priority = 2 * (NICE_MAX - NICE_MIN + 1);
136	          break;
137	        case SCHED_BATCH:
138	          snprintf(strschedp, sizeof(strschedp), "%s ", "batch");
139	          priority = (NICE_MAX - NICE_MIN + 1) + nice - NICE_MIN;
140	          break;
141	        case SCHED_RR:
142	          snprintf(strschedp, sizeof(strschedp), "%s ", "rt:rr");
143	          priority = priority - 99;
144	          break;
145	#ifdef SCHED_DEADLINE
146	        case SCHED_DEADLINE:
147	          snprintf(strschedp, sizeof(strschedp), "%s ", "rt:deadline");
148	          break;
149	#endif
150	        default:
151	          snprintf(strschedp, sizeof(strschedp), "%s ", "????");
152	          break;
153	      }
154	      lptr += sprintf(lptr, "%s ", strschedp);
155	      if (tdata != NULL) {
156	        tdata->lines[tdata->numlines].val[5] = strdup(strschedp);
157	        tdata->lines[tdata->numlines].val[6] = malloc(10);
158	        snprintf(tdata->lines[tdata->numlines].val[6], 9, "%i", priority);
159	      }
160	      break;
161	    default:
162	      break;
163	  } /* switch on fieldcnr */
164	  procfile_fields = strtok_r(NULL, toksep, &strtokptr);
165	} /* while on proc_fields != NULL */
166	prnt("%s\n", prntline);
167	if (tdata != NULL) {
168	  tdata->numlines++;
169	}
170	} /*decode_procstat */
