172	void read_statfile(char *fname, int debug, telnet_printfunc_t prnt, webdatadef_t *tdata)
173	{
174	FILE *procfile;
175	char arecord[1024];
176	
177	    procfile=fopen(fname,"r");
178	    if (procfile == NULL)
179	       {
180	       prnt("Error: Couldn't open %s %i %s\n",fname,errno,strerror(errno));
181	       return;
182	       }    
183	    if ( fgets(arecord,sizeof(arecord),procfile) == NULL)
184	       {
185	       prnt("Error: Nothing read from %s %i %s\n",fname,errno,strerror(errno));
186	       fclose(procfile);
187	       return;
188	       }    
189	    fclose(procfile);
190	    decode_procstat(arecord, debug, prnt, tdata);
191	}
